\langle q_0,q_1,...,q_m-1\rangle &amp;lt; f&amp;#x27; \leq \langle q_0,q_1,...,q_m\rangle,&amp;amp;\\[2ex]
&amp;amp;{\rm if}\ m \ {\rm is\ even},\\[2ex]
\langle q_0,q_1,...,q_m+1\rangle &amp;lt; f&amp;#x27; \leq \langle q_0,q_1,...,q_{m-1}\rangle,&amp;amp;\\[2ex]
&amp;amp;{\rm if}\ m \ {\rm is\ odd}
\end{aligned}
